import { writeOutput } from "./codegen";

const DOCS_URL = "https://api-docs.podchaser.com/docs/authorization/";
const PLACEHOLDER_VALUE =
  "vm0placeholderPodchaserToken00000000000000000000000000a";

function generateTypeScript(): string {
  const lines: string[] = [
    "// Auto-generated from Podchaser API docs.",
    `// Source: ${DOCS_URL}`,
    "// Regenerate: cd turbo && pnpm -F @vm0/firewalls-generator generate:podchaser",
    "//",
    "// DO NOT EDIT THIS FILE MANUALLY.",
    "",
    'import type { FirewallConfig } from "../contracts/firewalls";',
    "",
    "export const podchaserFirewall: FirewallConfig = {",
    '  name: "podchaser",',
    '  description: "Podchaser Podcast API",',
    "  placeholders: {",
    `    PODCHASER_TOKEN: "${PLACEHOLDER_VALUE}",`,
    "  },",
    "  apis: [",
    "    {",
    '      base: "https://api.podchaser.com",',
    "      auth: {",
    "        headers: {",
    '          Authorization: "Bearer ${{ secrets.PODCHASER_TOKEN }}",',
    "        },",
    "      },",
    "      permissions: [],",
    "    },",
    "  ],",
    "};",
    "",
  ];
  return lines.join("\n");
}

export async function generate(): Promise<void> {
  console.error("Generating Podchaser firewall config...");
  const ts = generateTypeScript();
  writeOutput("podchaser", ts, import.meta.dirname);
}
